<script setup lang="ts">
import { ref } from 'vue'; import { useRoute,useRouter } from 'vue-router'; import { useAuthStore } from '@/stores/auth'; import { useMock } from '@/services/supabase'
const email=ref(useMock?'ciudadano@demo.com':''); const password=ref(useMock?'demo1234':''); const auth=useAuthStore(); const router=useRouter(); const route=useRoute(); const sending=ref(false)
async function submit(){sending.value=true; if(await auth.signIn(email.value,password.value)) await router.push(String(route.query.redirect||'/app')); sending.value=false}
</script>
<template><div class="auth-page"><router-link to="/" class="back">← Volver</router-link><div class="auth-card"><div class="auth-brand"><span>✚</span><h1>Manta Cuida IA</h1><p>Ingresa para consultar y dar seguimiento a tus casos.</p></div><form @submit.prevent="submit"><div class="form-group"><label>Correo</label><input v-model="email" type="email" class="form-input" required/></div><div class="form-group"><label>Contraseña</label><input v-model="password" type="password" class="form-input" required/></div><p v-if="auth.error" class="form-error">{{ auth.error }}</p><button class="btn btn-primary w-full" :disabled="sending">{{sending?'Ingresando...':'Ingresar'}}</button></form><div v-if="useMock" class="demo"><strong>Cuentas demo</strong><p>Ciudadano: ciudadano@demo.com</p><p>Operador: operador@demo.com</p><p>Admin: admin@demo.com</p><p>Contraseña: demo1234</p></div><p class="bottom">¿No tienes cuenta? <router-link to="/registro">Regístrate</router-link></p></div></div></template>
<style scoped>.auth-page{min-height:100vh;background:linear-gradient(135deg,#082f49,#0e7490);display:grid;place-items:center;padding:1rem}.back{position:fixed;top:1rem;left:1rem;color:#fff}.auth-card{width:min(430px,100%);background:#fff;border-radius:18px;padding:2rem;box-shadow:0 24px 70px rgba(0,0,0,.22)}.auth-brand{text-align:center;margin-bottom:1.5rem}.auth-brand>span{display:grid;place-items:center;width:52px;height:52px;margin:auto;background:#2dd4bf;border-radius:14px;color:#083344;font-size:1.6rem}.auth-brand h1{color:#082f49;margin:.6rem 0}.auth-brand p,.bottom{color:#64748b;font-size:.86rem}.demo{background:#ecfeff;padding:.8rem;border-radius:10px;margin-top:1rem;font-size:.76rem;color:#155e75}.bottom{text-align:center;margin-top:1rem}</style>
